1	// ---- Domain types ----
2	type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	
9	type QuoteStep = { op: "quote"; items: Item[] };
10	type Scenario = {
